import ldap

def search_users_by_username(ldap_server, bind_dn, bind_password, search_base, username):
    try:
        # Initialize LDAP connection
        ldap_conn = ldap.initialize(ldap_server)
        ldap_conn.set_option(ldap.OPT_PROTOCOL_VERSION, 3)
        ldap_conn.set_option(ldap.OPT_REFERRALS, 0)
        
        # Bind to the directory
        ldap_conn.simple_bind_s(bind_dn, bind_password)
        
        # Search for user by username
        search_filter = f"(uid={username})"
        attributes = ['uid', 'cn', 'mail', 'givenName', 'sn']
        
        result = ldap_conn.search_s(search_base, ldap.SCOPE_SUBTREE, search_filter, attributes)
        
        # Process results
        users = []
        for dn, entry in result:
            if entry:
                user_info = {
                    'dn': dn,
                    'uid': entry.get('uid', [None])[0],
                    'cn': entry.get('cn', [None])[0],
                    'mail': entry.get('mail', [None])[0],
                    'givenName': entry.get('givenName', [None])[0],
                    'sn': entry.get('sn', [None])[0]
                }
                users.append(user_info)
        
        # Close connection
        ldap_conn.unbind_s()
        
        return users
        
    except ldap.INVALID_CREDENTIALS:
        raise Exception("Invalid credentials")
    except ldap.NO_SUCH_OBJECT:
        return []
    except Exception as e:
        raise Exception(f"LDAP search failed: {str(e)}")